// One-click BT-source switch for the production-scene visual A/B.
//
// Both sources replay through the SAME recorded-bodies path
// (SkeletonMerger.ignoreRecordedBodies = false); the only difference is which
// session root is played:
//   k4abt   -> the original recording (bodies_main = recorded k4abt output)
//   RTMPose -> a hardlinked copy whose bodies_main was generated by RTMPose
//
// Menu: FloatingVectors/Eval BT/... — works during play mode; stops playback,
// repoints the recorder, reloads tracks and restarts playback (~2-5 s).
// NOTE: live k4abt workers are NOT available on this machine (K4A wrapper / BT
// SDK not installed), so "k4abt" here is the recorded output.

using UnityEditor;
using UnityEngine;

namespace BodyTracking.Eval.Rtmpose
{
    public static class EvalBtSwitch
    {
        const string RootK4abt = "D:/Dropbox/projects/ICC/Recordings/RecordingBase/2026-07-14_15-50-24";
        const string RootRtmpose = "D:/FVICC_eval/15-50-24-rtmpose";

        [MenuItem("FloatingVectors/Eval BT/Use k4abt bodies", priority = 1)]
        public static void UseK4abt() => Switch(RootK4abt, "k4abt");

        [MenuItem("FloatingVectors/Eval BT/Use RTMPose bodies", priority = 2)]
        public static void UseRtmpose() => Switch(RootRtmpose, "RTMPose");

        [MenuItem("FloatingVectors/Eval BT/Status", priority = 20)]
        public static void Status()
        {
            var rec = Object.FindObjectsByType<PointCloud.SensorRecorder>(FindObjectsSortMode.None);
            var mg = Object.FindObjectsByType<SkeletonMerger>(FindObjectsSortMode.None);
            string root = rec.Length > 0 ? rec[0].playbackFolderPath : "(no recorder)";
            string mode = root.Contains("rtmpose") ? "RTMPose" : "k4abt";
            Debug.Log($"[EvalBT] source={mode} root={root} " +
                      (rec.Length > 0 ? $"state={rec[0].CurrentState} playhead={rec[0].CurrentPlayheadSeconds:F1}s " : "") +
                      (mg.Length > 0 ? $"persons={mg[0].PersonCount} ignoreRecordedBodies={mg[0].ignoreRecordedBodies}" : ""));
        }

        static void Switch(string root, string label)
        {
            if (!Application.isPlaying)
            {
                Debug.LogWarning("[EvalBT] enter Play mode first, then switch.");
                return;
            }
            var recs = Object.FindObjectsByType<PointCloud.SensorRecorder>(FindObjectsSortMode.None);
            var mergers = Object.FindObjectsByType<SkeletonMerger>(FindObjectsSortMode.None);
            if (recs.Length == 0) { Debug.LogError("[EvalBT] no SensorRecorder in scene"); return; }
            var rec = recs[0];

            foreach (var m in mergers) m.ignoreRecordedBodies = false; // recorded-bodies path for both sources

            if (rec.IsPlaying) rec.TogglePlay();     // stop
            rec.playbackFolderPath = root;
            rec.Load();                              // reload tracks from the new root
            rec.TogglePlay();                        // play from the beginning
            Debug.Log($"[EvalBT] switched to {label} bodies, playing '{root}'");
        }
    }
}
